import{_ as e,c as r,o as s,a5 as a}from"./chunks/framework.CgT1UzWm.js";const p=JSON.parse('{"title":"NpgsqlRest Deep Dive — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"Six NpgsqlRest configurations benchmarked head to head: 3.4.7 vs 3.21.0, routine source vs the new SQL file source, AOT vs JIT. The SQL file source is up to 33% faster.","frontmatter":{"layout":"doc","outline":[2,3],"title":"NpgsqlRest Deep Dive — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"Six NpgsqlRest configurations benchmarked head to head: 3.4.7 vs 3.21.0, routine source vs the new SQL file source, AOT vs JIT. The SQL file source is up to 33% faster.","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/npgsqlrest.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/npgsqlrest.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"NpgsqlRest Deep Dive — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"property":"og:description","content":"Six NpgsqlRest configurations benchmarked head to head: 3.4.7 vs 3.21.0, routine source vs the new SQL file source, AOT vs JIT. The SQL file source is up to 33% faster."}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest Deep Dive — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"name":"twitter:description","content":"Six NpgsqlRest configurations benchmarked head to head: 3.4.7 vs 3.21.0, routine source vs the new SQL file source, AOT vs JIT. The SQL file source is up to 33% faster."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"blog/benchmarks-2026-07/npgsqlrest.md","filePath":"blog/benchmarks-2026-07/npgsqlrest.md","lastUpdated":1782480183000}'),i={name:"blog/benchmarks-2026-07/npgsqlrest.md"};function n(o,t,l,d,h,g){return s(),r("div",null,t[0]||(t[0]=[a('<h1 id="npgsqlrest-deep-dive-six-configurations-three-questions" tabindex="-1">NpgsqlRest Deep Dive: Six Configurations, Three Questions <a class="header-anchor" href="#npgsqlrest-deep-dive-six-configurations-three-questions" aria-label="Permalink to &quot;NpgsqlRest Deep Dive: Six Configurations, Three Questions&quot;">​</a></h1><p class="blog-meta"><span class="tag">Benchmark</span> · <span class="tag">NpgsqlRest</span> · <span class="tag">July 2026</span></p><p>Part of the <a href="/blog/benchmarks-2026-07/">PostgreSQL REST API Benchmark, July 2026</a> series.</p><p>This round tested six NpgsqlRest configurations side by side — same database, same endpoints, same load — to answer three questions with data instead of intuition:</p><ol><li><strong>Did eighteen releases of features cost any performance?</strong> (3.4.7 vs 3.21.0)</li><li><strong>What does the new <a href="https://npgsqlrest.github.io/guide/sql-files" target="_blank" rel="noreferrer">SQL file source</a> cost — or save?</strong> (routine vs file endpoints)</li><li><strong>Is the AOT build still the memory winner, and does JIT still hold a speed edge?</strong></li></ol><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Variant</th><th>Version</th><th>Endpoint source</th><th>Build</th><th>Port</th></tr></thead><tbody><tr><td>Routine AOT 3.4.7</td><td>3.4.7</td><td>PostgreSQL functions</td><td>Native AOT</td><td>5005</td></tr><tr><td>Routine JIT 3.4.7</td><td>3.4.7</td><td>PostgreSQL functions</td><td>CoreCLR JIT</td><td>5006</td></tr><tr><td>Routine AOT 3.21.0</td><td>3.21.0</td><td>PostgreSQL functions</td><td>Native AOT</td><td>5007</td></tr><tr><td>Routine JIT 3.21.0</td><td>3.21.0</td><td>PostgreSQL functions</td><td>CoreCLR JIT</td><td>5008</td></tr><tr><td><strong>SQL Files AOT 3.21.0</strong></td><td>3.21.0</td><td><strong>Raw <code>.sql</code> statements</strong></td><td>Native AOT</td><td>5009</td></tr><tr><td><strong>SQL Files JIT 3.21.0</strong></td><td>3.21.0</td><td><strong>Raw <code>.sql</code> statements</strong></td><td>CoreCLR JIT</td><td>5010</td></tr></tbody></table></div></div><p>All six run from configuration alone — <a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/npgsqlrest-routine-jit-v3.21.0/appsettings.json" target="_blank" rel="noreferrer">21 lines of appsettings.json</a> for the routine variants; the file variants add <a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_sql_files" target="_blank" rel="noreferrer">six plain <code>.sql</code> files</a> whose statements are kept identical to the function bodies. Before the run, we byte-compared responses between routine and file endpoints across every deterministic scenario: <strong>identical</strong>. Whatever performance difference appears below is machinery, not output.</p><p><strong>The verdict in one sentence: version upgrades were performance-neutral, AOT still halves memory — and the SQL file source turned out to be up to a third faster than calling functions.</strong></p><h2 id="question-1-3-4-7-→-3-21-0-—-did-features-cost-speed" tabindex="-1">Question 1: 3.4.7 → 3.21.0 — did features cost speed? <a class="header-anchor" href="#question-1-3-4-7-→-3-21-0-—-did-features-cost-speed" aria-label="Permalink to &quot;Question 1: 3.4.7 → 3.21.0 — did features cost speed?&quot;">​</a></h2><p>No. Across 38 combinations the routine-source variants of both versions are statistically inseparable:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>perf-test, 1 record</th><th style="text-align:right;">3.4.7 JIT</th><th style="text-align:right;">3.21.0 JIT</th><th style="text-align:right;">Δ</th></tr></thead><tbody><tr><td>100 VU</td><td style="text-align:right;">2,620 req/s</td><td style="text-align:right;">2,617 req/s</td><td style="text-align:right;">−0.1%</td></tr><tr><td>Minimal baseline, 100 VU</td><td style="text-align:right;">15,374</td><td style="text-align:right;">15,280</td><td style="text-align:right;">−0.6%</td></tr><tr><td>Minimal baseline, 100 VU (AOT)</td><td style="text-align:right;">15,327</td><td style="text-align:right;">15,549</td><td style="text-align:right;">+1.4%</td></tr></tbody></table></div></div><p>Every delta between versions lands inside run-to-run noise. Eighteen minor releases — the SQL file source itself, the MCP server, the SQL test runner, watch mode, Dart client generation — added <strong>zero measurable overhead</strong> to the hot path. That is the finding: not faster, but feature growth without performance decay, which is rarer.</p><p><em>(A methodological confession: our pre-run smoke tests on ARM/emulated hardware suggested 3.21.0 was 6–13% faster. Native x86 falsified that. Preliminary numbers on non-target hardware are noise — treat them accordingly.)</em></p><h2 id="question-2-routine-vs-sql-files-—-the-finding-of-the-round" tabindex="-1">Question 2: Routine vs SQL files — the finding of the round <a class="header-anchor" href="#question-2-routine-vs-sql-files-—-the-finding-of-the-round" aria-label="Permalink to &quot;Question 2: Routine vs SQL files — the finding of the round&quot;">​</a></h2><p>The SQL file source executes the statement directly; the routine source wraps it in a PostgreSQL function call. Same database work — the functions are <code>language sql</code> and inlinable — so we expected parity. Instead:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>perf-test, JIT 3.21.0</th><th style="text-align:right;">Routine</th><th style="text-align:right;">SQL Files</th><th style="text-align:right;">Δ</th></tr></thead><tbody><tr><td>50 VU, 1 record</td><td style="text-align:right;">2,701</td><td style="text-align:right;">3,621</td><td style="text-align:right;"><strong>+34%</strong></td></tr><tr><td>100 VU, 1 record</td><td style="text-align:right;">2,617</td><td style="text-align:right;">3,467</td><td style="text-align:right;"><strong>+32%</strong></td></tr><tr><td>200 VU, 1 record</td><td style="text-align:right;">2,593</td><td style="text-align:right;">3,453</td><td style="text-align:right;"><strong>+33%</strong></td></tr><tr><td>100 VU, 10 records</td><td style="text-align:right;">1,438</td><td style="text-align:right;">1,457</td><td style="text-align:right;">+1.3%</td></tr><tr><td>100 VU, 100 records</td><td style="text-align:right;">166</td><td style="text-align:right;">166</td><td style="text-align:right;">0%</td></tr><tr><td>100 VU, 500 records</td><td style="text-align:right;">35</td><td style="text-align:right;">35</td><td style="text-align:right;">0%</td></tr></tbody></table></div></div><p>And on the 20-parameter query-string scenario:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>params</th><th style="text-align:right;">Routine</th><th style="text-align:right;">SQL Files</th><th style="text-align:right;">Δ</th></tr></thead><tbody><tr><td>50 VU</td><td style="text-align:right;">11,435</td><td style="text-align:right;">14,437</td><td style="text-align:right;"><strong>+26%</strong></td></tr><tr><td>200 VU</td><td style="text-align:right;">12,254</td><td style="text-align:right;">12,692</td><td style="text-align:right;">+3.6%</td></tr></tbody></table></div></div><p>The gradient tells the story. The advantage is enormous where requests are small and frequent (1 record: +33%), shrinks as payloads grow (10 records: +1%), and disappears entirely when response size dominates (100+ records: 0%). The gap also correlates with parameter count. This is the signature of <strong>fixed per-request invocation overhead</strong> in the routine path — command construction and parameter wrapping around the function call — being amortized away as each request carries more data. It is <em>not</em> PostgreSQL function-call overhead: these functions inline, and the 100-record parity proves the database does identical work in both paths.</p><p><strong>Practical implication:</strong> for small-payload, high-frequency endpoints — exactly the profile of most CRUD and lookup APIs — the SQL file source is the fastest way to run NpgsqlRest, and it lifted these variants to <strong>#2 and #3 in the entire 20-service field</strong> on the headline perf-test scenario at 100–200 VU, behind only <a href="/blog/benchmarks-2026-07/fastapi.html">FastAPI&#39;s</a> 8-worker pool.</p><p><strong>A question this opens for the next round:</strong> with a consistent 30% gap established, a raw-query control in another stack (Dapper executing the statement directly instead of calling the function) would isolate how much of the routine path&#39;s cost is general to PostgreSQL clients versus specific to NpgsqlRest&#39;s routine machinery.</p><h2 id="question-3-aot-vs-jit" tabindex="-1">Question 3: AOT vs JIT <a class="header-anchor" href="#question-3-aot-vs-jit" aria-label="Permalink to &quot;Question 3: AOT vs JIT&quot;">​</a></h2><p>Throughput: parity, with nuance at the extremes.</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Scenario</th><th style="text-align:right;">AOT (file, 3.21.0)</th><th style="text-align:right;">JIT (file, 3.21.0)</th></tr></thead><tbody><tr><td>perf-test 1 VU, 1 rec</td><td style="text-align:right;">658 req/s</td><td style="text-align:right;"><strong>753 req/s</strong> (+14%)</td></tr><tr><td>perf-test 200 VU, 1 rec</td><td style="text-align:right;"><strong>3,481</strong></td><td style="text-align:right;">3,453</td></tr><tr><td>Minimal 100 VU</td><td style="text-align:right;"><strong>15,776</strong></td><td style="text-align:right;">15,556</td></tr></tbody></table></div></div><p>JIT keeps a measurable single-connection edge (its tiered compilation optimizes the hottest path further than AOT&#39;s ahead-of-time code), while AOT matches or edges it under real concurrency. But the decisive difference is memory:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Variant</th><th style="text-align:right;">Peak MB</th><th style="text-align:right;">Avg MB</th></tr></thead><tbody><tr><td>Routine AOT 3.4.7</td><td style="text-align:right;">156</td><td style="text-align:right;">62</td></tr><tr><td>SQL Files AOT 3.21.0</td><td style="text-align:right;">155</td><td style="text-align:right;">62</td></tr><tr><td>Routine AOT 3.21.0</td><td style="text-align:right;">168</td><td style="text-align:right;">65</td></tr><tr><td>Routine JIT 3.4.7</td><td style="text-align:right;">230</td><td style="text-align:right;">124</td></tr><tr><td>SQL Files JIT 3.21.0</td><td style="text-align:right;">225</td><td style="text-align:right;">125</td></tr><tr><td>Routine JIT 3.21.0</td><td style="text-align:right;">280</td><td style="text-align:right;">129</td></tr></tbody></table></div></div><p><strong>AOT runs on half the memory of JIT</strong> — 62 MB average versus ~125 MB — consistent across versions and endpoint sources. The January guidance stands, now with more data behind it: pick AOT for density, containers, and cold starts; pick JIT if single-connection latency is the last percent you need. Throughput will not decide this for you.</p><h2 id="against-the-field" tabindex="-1">Against the field <a class="header-anchor" href="#against-the-field" aria-label="Permalink to &quot;Against the field&quot;">​</a></h2><p>Context from the <a href="/blog/benchmarks-2026-07/analysis.html">overall analysis</a>, using the same-driver .NET baselines as the fairest comparison — NpgsqlRest and the <a href="/blog/benchmarks-2026-07/dotnet.html">.NET Minimal API apps</a> all sit on Npgsql:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>perf-test, 100 VU, 1 record</th><th style="text-align:right;">req/s</th></tr></thead><tbody><tr><td>FastAPI (field leader)</td><td style="text-align:right;">5,109</td></tr><tr><td><strong>NpgsqlRest SQL Files AOT</strong></td><td style="text-align:right;"><strong>3,524</strong> (#2)</td></tr><tr><td><strong>NpgsqlRest SQL Files JIT</strong></td><td style="text-align:right;"><strong>3,467</strong> (#3)</td></tr><tr><td>NpgsqlRest Routine JIT</td><td style="text-align:right;">2,617</td></tr><tr><td>.NET 10 Minimal API + Dapper (hand-written)</td><td style="text-align:right;">2,255</td></tr><tr><td>.NET 10 Minimal API + EF Core (hand-written)</td><td style="text-align:right;">2,230</td></tr></tbody></table></div></div><p>The routine source — the <em>slower</em> NpgsqlRest path — outperforms hand-written Dapper endpoints on the same driver by 16%. The file source beats them by more than 50%. The zero-code approach is not a convenience trade-off here; it is faster than writing the code yourself, because the generic pipeline skips materialization work that per-endpoint code tends to accumulate.</p><p>On pure routing (minimal baseline) the field compresses: NpgsqlRest lands 15,280–15,776 req/s (#6–#12 in a pack where #3–#12 span 6%), behind <a href="/blog/benchmarks-2026-07/go.html">Go&#39;s</a> 16,882. Nested, large-payload, and POST scenarios sit mid-pack — payload-dominated categories where most of the field converges anyway (see <a href="/blog/benchmarks-2026-07/results.html">Raw Results</a>).</p><h2 id="the-other-zero-code-platform-postgrest-head-to-head" tabindex="-1">The other zero-code platform: PostgREST head-to-head <a class="header-anchor" href="#the-other-zero-code-platform-postgrest-head-to-head" aria-label="Permalink to &quot;The other zero-code platform: PostgREST head-to-head&quot;">​</a></h2><p>NpgsqlRest and <a href="/blog/benchmarks-2026-07/postgrest.html">PostgREST</a> are the only two services in this field where the API is <em>defined in the database</em> and the entire &quot;application&quot; is a configuration file — 12 lines for PostgREST, 21 for NpgsqlRest. That makes this the benchmark&#39;s only same-paradigm comparison, and it splits cleanly by workload type (NpgsqlRest = best variant per scenario, reference combos):</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Scenario</th><th style="text-align:right;">PostgREST</th><th style="text-align:right;">NpgsqlRest</th><th style="text-align:right;">Ratio</th></tr></thead><tbody><tr><td>Minimal baseline (100 VU)</td><td style="text-align:right;">6,986</td><td style="text-align:right;">15,776</td><td style="text-align:right;"><strong>2.3×</strong></td></tr><tr><td>perf-test (100 VU, 1 rec)</td><td style="text-align:right;">1,322</td><td style="text-align:right;">3,524</td><td style="text-align:right;"><strong>2.7×</strong></td></tr><tr><td>Many params (50 VU)</td><td style="text-align:right;">3,726</td><td style="text-align:right;">14,437</td><td style="text-align:right;"><strong>3.9×</strong></td></tr><tr><td>Large payload (25 VU, 100 KB)</td><td style="text-align:right;">729</td><td style="text-align:right;">1,368</td><td style="text-align:right;"><strong>1.9×</strong></td></tr><tr><td>POST body (50 VU, 10 rec)</td><td style="text-align:right;">3,867</td><td style="text-align:right;">4,058</td><td style="text-align:right;">1.05×</td></tr><tr><td>Nested JSON (50 VU, d1)</td><td style="text-align:right;">1,633</td><td style="text-align:right;">1,640</td><td style="text-align:right;">1.00×</td></tr><tr><td>Avg memory</td><td style="text-align:right;"><strong>57 MB</strong></td><td style="text-align:right;">62 MB (AOT)</td><td style="text-align:right;">~parity</td></tr></tbody></table></div></div><p>The pattern is consistent with everything else in this series: where the response payload dominates (nested, POST with echo), the two are indistinguishable — both delegate JSON construction to PostgreSQL and ship bytes. Where the <em>server</em> dominates — routing, query-string parsing, small rapid responses — NpgsqlRest is 2–4× ahead, with the params scenario (20 typed parameters per request) showing the widest gap in the entire comparison.</p><p>Memory is honest parity: PostgREST&#39;s Haskell runtime averages 57 MB, NpgsqlRest AOT 62 MB. Both are in the field&#39;s most frugal tier.</p><p>The fair conclusion: the database-first paradigm is not intrinsically slow — one implementation of it sits at #2 in the field-wide headline ranking while the other sits at #20. Paradigm sets the floor of effort; implementation sets the ceiling of performance.</p><h2 id="cost-of-ownership" tabindex="-1">Cost of ownership <a class="header-anchor" href="#cost-of-ownership" aria-label="Permalink to &quot;Cost of ownership&quot;">​</a></h2><p>From the <a href="/blog/benchmarks-2026-07/analysis.html#performance-per-line-of-code">lines-of-code comparison</a>: the routine variants need <strong>21 lines of configuration</strong> and zero application code. The SQL file variants add the six <code>.sql</code> files — statements you would have written anyway — for a total of 140 physical lines. The hand-written alternatives implementing the same six endpoints range from 102 (Fastify) to 303 (Go).</p><h2 id="verdict" tabindex="-1">Verdict <a class="header-anchor" href="#verdict" aria-label="Permalink to &quot;Verdict&quot;">​</a></h2><ul><li><strong>Upgrade freely</strong>: 3.21.0 carries eighteen releases of features at zero hot-path cost.</li><li><strong>Prefer the SQL file source</strong> for small-payload, high-frequency endpoints: up to +33% throughput, #2 in the field, and the source format (a plain SQL file) is the simplest one yet.</li><li><strong>AOT for memory</strong> (62 MB average — half of JIT), <strong>JIT for single-connection latency</strong>. Throughput is a tie.</li><li>The zero-code pipeline outran same-driver hand-written .NET endpoints in every configuration tested.</li></ul><h2 id="explore-on-github" tabindex="-1">Explore on GitHub <a class="header-anchor" href="#explore-on-github" aria-label="Permalink to &quot;Explore on GitHub&quot;">​</a></h2><p>Everything this page claims can be checked against the running code and the raw output:</p><ul><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/npgsqlrest-routine-jit-v3.21.0" target="_blank" rel="noreferrer">Routine-source configuration</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/npgsqlrest-file-jit-v3.21.0" target="_blank" rel="noreferrer">SQL-file-source configuration</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_sql_files" target="_blank" rel="noreferrer">The raw SQL endpoint files</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_postgres/init.sql" target="_blank" rel="noreferrer">The PostgreSQL functions every service calls</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/scripts" target="_blank" rel="noreferrer">k6 load scripts</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/results/202607131327" target="_blank" rel="noreferrer">This run&#39;s per-test k6 summaries</a> — filter by this service&#39;s name</li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_k6/results/202607131327/results.csv" target="_blank" rel="noreferrer">Complete dataset: results.csv</a></li></ul><hr><p><strong>Series:</strong> <a href="/blog/benchmarks-2026-07/">Introduction</a> · <a href="/blog/benchmarks-2026-07/analysis.html">Overall Analysis</a> · <a href="/blog/benchmarks-2026-07/results.html">Raw Results</a></p><p><strong>Next:</strong> <a href="/blog/benchmarks-2026-07/analysis.html">Overall Analysis →</a></p>',49)]))}const u=e(i,[["render",n]]);export{p as __pageData,u as default};
